// ---------------------------------------------------------------------------
// Cameras (hand-mirrored from nexus-config / nexus-engine).
// Source of truth: crates/nexus-config/src/lib.rs CameraConfig.
// ---------------------------------------------------------------------------

export interface VisualPromptRef {
  id: string;
  label: string;
}

// Mirrors the engine-side `nexus_config::ModelConfig` shape so the camera
// editor can override every structural detector field per-camera, not just
// `kind`. All fields are optional — anything the UI omits falls back to the
// engine's defaults via serde defaults on the Rust side. The index
// signature is kept for forward compat with any field the engine adds
// before the UI types are regenerated.
export interface ModelOverride {
  kind?: string;
  pack_path?: string | null;
  preset?: string;
  input_width?: number;
  input_height?: number;
  score_threshold?: number;
  top_k?: number | null;
  [k: string]: unknown;
}

export interface CameraConfig {
  /// Server-assigned i64 row id. New cameras created from the UI
  /// MUST start with `0` and call `createCamera` (POST /cameras);
  /// the engine assigns the real id from SQLite's `INTEGER
  /// PRIMARY KEY` rowid alias and returns the populated body.
  /// Subsequent edits go via `updateCamera` (PUT /cameras/{id}).
  /// Anything non-numeric in the path is rejected by the engine's
  /// `Path<i64>` extractor with HTTP 400, so the UI never invents
  /// a placeholder like `cam-<ip>` — that flow has been broken
  /// since `CameraId` switched from `String` to `i64`.
  id: number;
  name: string;
  url: string;
  enabled?: boolean;
  max_fps?: number;
  prompts?: string[];
  visual_prompts?: VisualPromptRef[];
  model_override?: ModelOverride | null;
  parking_lot_mode?: boolean;
  // Per-camera override for the engine-wide `tracker.static_object.anchor_ttl_secs`.
  // Anchors with no matching observation older than this many seconds get
  // swept on the next classify tick. Leave undefined to inherit the engine
  // default (3600s as of writing). Restart required — the supervisor
  // reads this once at start and the reconciler only respawns on URL change.
  anchor_ttl_secs?: number | null;
  zones?: ZoneConfig[];
  // Legacy / extension fields engine may include but UI doesn't yet model.
  [k: string]: unknown;
}

// ---------------------------------------------------------------------------
// Rules. Source of truth: crates/nexus-config/src/lib.rs RuleConfig.
// ---------------------------------------------------------------------------

export type RuleSeverity = "low" | "warning" | "critical";

export interface RuleConfig {
  id: string;
  name: string;
  when: string;
  severity?: RuleSeverity | string;
  /// Camera-id allow-list. Wire format is `Vec<i64>` (matches
  /// `CameraId = i64` in the engine); the UI MUST send JSON
  /// numbers, not strings — serde rejects a string array with
  /// HTTP 422 at the rule-create boundary. Use the existing
  /// numeric `CameraConfig.id` values directly.
  camera_filter?: number[] | null;
  zones?: string[] | null;
  min_track_age_ms?: number;
  consecutive_frames?: number;
  cooldown_ms?: number;
  enabled?: boolean;
  [k: string]: unknown;
}

