// ---------------------------------------------------------------------------
// ONVIF Media probe — authoritative stream enumeration via the
// camera's own GetProfiles + GetStreamUri SOAP calls. Skips the
// guess-12-paths brute force entirely. Engine handler:
// `crates/nexus-engine/src/discovery/mod.rs::post_probe_onvif`.
// ---------------------------------------------------------------------------

export interface ProbeOnvifRequest {
  /// Verbatim XAddrs URL the camera advertised during
  /// WS-Discovery (carried on `DiscoveredDevice.onvif_xaddrs`).
  xaddr: string;
  /// Mandatory — `GetProfiles` is gated on every shipped
  /// camera firmware I've seen; anonymous calls return
  /// `NotAuthorized`.
  username: string;
  password: string;
}

export interface OnvifMediaStream {
  /// ONVIF profile token (e.g. `"Profile_1"`, `"MainStream"`).
  token: string;
  /// Human-readable profile name (e.g. `"mainStream"`).
  name: string;
  /// RTSP URI as the camera reports it. **Has no credentials**
  /// embedded — the UI must inject `<user>:<pass>@` between
  /// `rtsp://` and the host before calling `cameras.add`.
  uri: string;
  /// Encoding from `VideoEncoderConfiguration.Encoding`
  /// (e.g. `"H264"`, `"H265"`). May be absent on profiles
  /// without a video encoder.
  codec?: string | null;
  /// `<width>x<height>` from the profile's resolution element
  /// (e.g. `"1920x1080"`). Absent on audio-only profiles.
  resolution?: string | null;
}

export interface ProbeOnvifResult {
  /// `true` IFF `streams` is non-empty. UI falls back to the
  /// brute-force RTSP path sweep whenever this is `false`.
  ok: boolean;
  streams: OnvifMediaStream[];
  /// Operator-facing failure reason (e.g. `"NotAuthorized"`,
  /// `"connect failed: timeout"`). Logged but not surfaced
  /// to the operator unless the RTSP fallback ALSO fails.
  error?: string | null;
}

// ---------------------------------------------------------------------------
// Prompt catalog. Mirrors `crates/nexus-engine/src/models_catalog.rs`
// `ModelPromptsCatalog` / `DetectorPromptInfo` — hand-kept in lockstep.
// ---------------------------------------------------------------------------

export interface ModelPromptsGroup {
  name: string;
  labels: string[];
}

export interface ModelPromptsEntry {
  kind: string;
  /// `true` for YOLO-World / YOLOE-text detectors that accept any
  /// user-supplied prompt; `false` for fixed-vocab kinds like
  /// closed-vocab YOLO or the PPE classifier ensemble.
  open_vocab: boolean;
  /// Every label this detector kind is known to emit (closed-vocab)
  /// or every baked prompt the detector recognises (open-vocab).
  /// Empty for `mock` / `yoloe_visual` / `classifier_ensemble`.
  prompts: string[];
  /// Optional groupings the UI can render as titled chip rows.
  groups: ModelPromptsGroup[];
  /// Operator-facing description of the detector. Shown beneath the
  /// chip strip in the camera form.
  note?: string | null;
  /// `true` iff the engine router built a layer for this kind at
  /// boot. Operators who pick an unloaded kind as an override won't
  /// see it take effect until the engine restarts; the UI uses this
  /// to surface a "restart engine to activate" hint.
  loaded: boolean;
}

export interface ModelPromptsCatalog {
  /// The default `inference.model.kind` from the engine's config —
  /// the kind every camera without a `model_override` runs against.
  default_kind: string;
  /// Stable-ordered list (the array form is preferred for dropdown
  /// rendering — see `by_kind` for keyed lookup).
  kinds: ModelPromptsEntry[];
  /// Same entries as `kinds`, indexed by `kind` for O(1) lookup.
  by_kind: Record<string, ModelPromptsEntry>;
}

